var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"……돌아왔군. 집이야.","JPN":"……帰ってきたぜ。家だ。","ENG":"Finally... We're home.","TWN":"……回來了，到家了。"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"하아……. 무사귀환이라니 꿈만 같네요.","JPN":"はあ……無事帰還だなんて、夢みたいですね。","ENG":"*Sigh...* Can't believe we made it back.","TWN":"呼……竟然可以平安回來，好像真做夢一樣。"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"그 괴물이 튀어나왔을 땐 정말 다 죽는 줄 알았다고요.","JPN":"あの化け物が飛び出してきた時には本当に全員死ぬかと思いました。","ENG":"I thought we were goners when that giant monster suddenly appeared.","TWN":"那個怪物冒出來的時候，我真的以為我們都會死掉。"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"크큭. 이게 다 내가 준비해 간 폭탄 덕분인 줄 알아. 평생 감사하고 살아라, 이 자식아.","JPN":"ククッ、全部俺が用意した爆弾のおかげなんだぞ。一生感謝しろ、この野郎。","ENG":"Hahah. It's all thanks to my bombs, you hear? You ought to thank me for the rest of your life that you're still alive!","TWN":"咳咳，這都是拜我準備的炸彈所賜，記得要感謝我一輩子，你這臭小子。"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_PRIDE"}}}},{"id":"L6_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"그 많은 폭약을 거기까지 실어 나른 건 저라고요.","JPN":"その大量の爆薬をあそこまで運んだのは僕ですよ。","ENG":"Hey, I'm the one who moved all that gunpowder, you know.","TWN":"把那麼多炸藥運到那裡的是我欸！"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_PRIDE"}}}},{"id":"L7_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"그래도 뭐, 장교님께는 전부 와트 씨의 공이었다고 말씀드릴게요.","JPN":"でもまあ、将校には全部ワットさんの功績だったって言ってあげますよ。","ENG":"But, either way, I'll tell Officer Rashford that it was all you.","TWN":"反正我會跟軍官說，全都是華特先生的功勞啦！"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_PRIDE"}}}},{"id":"L8_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"난 됐어. 그런 공로는 너나 받아라.","JPN":"俺はいい。功績はお前が持っていけ。","ENG":"Nah. You should take the credit.","TWN":"不需要，那些功勞送你吧。"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_HATE"}}}},{"id":"L9_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"네? 왜요?","JPN":"えっ？　なんでですか？","ENG":"Huh? But why?","TWN":"嗯？為什麼？"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_HATE"}}}},{"id":"L10_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"왜긴 왜야? 나 같은 중늙은이가 출세해서 뭐 하게?","JPN":"なんでって、俺みたいな中年が出世して何するんだよ。","ENG":"Why not? What's an old man like me supposed to do climbing up the ladder now?","TWN":"什麼爲什麼？我這個老頭子有什麼好爭的？"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_PRIDE"}}}},{"id":"L11_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"아직 젊은 녀석이 평생 시골 수비대에서 썩을 생각이냐? 수도로 가서 큰일도 해 봐야지.","JPN":"まだ若いのに、一生田舎の守備隊で腐ってるつもりなのか？　首都で大きな仕事もやってみねえとな。","ENG":"But you. You're not thinking of staying here being a Border Guard forever, right? There are big things waiting for you in the capital.","TWN":"你還年輕，難道一輩子都打算待在鄉下的護衛隊嗎？你應該去首都闖闖。"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"와트 씨…","JPN":"ワットさん……","ENG":"Mr. Watt...","TWN":"華特先生…"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NAMED","text":{"KOREA":"다들 여기까지 오느라 수고 많았네.","JPN":"みんな、ここまでご苦労じゃったのう。","ENG":"You all did well coming back home safely.","TWN":"大家此行都辛苦了。"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NAMED","text":{"KOREA":"짐을 푸는 대로 식사나 하지.","JPN":"荷をほどき次第食事にしよう。","ENG":"Let's go eat after unpacking.","TWN":"放下行李就來吃飯吧。"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"GUARD_BORDER_NULL_NULL","text":{"KOREA":"하하, 감자 냄새가 이렇게 반가울 줄이야.","JPN":"はは、ジャガイモの匂いがこんなに嬉しいなんてなぁ。","ENG":"Ha ha! Who would've thought the smell of potatoes could be so good!","TWN":"哈哈，沒想到聞到馬鈴薯的味道還會這麼開心。"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"GUARD_BORDER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"촌장, 내가 말한 건 준비해 뒀나?","JPN":"村長、私が言ったものは用意してくれたか？","ENG":"Chief, did you prepare what I asked for?","TWN":"村長，我說的東西你有準備嗎？"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NAMED","text":{"KOREA":"물론이지. 술이 아주 잘 익었더군. 대원들이 실컷 마시고도 남을 걸세.","JPN":"もちろんじゃ。酒がよく熟成しておった。隊員が存分に飲んでも余るじゃろう。","ENG":"Of course. The ale turned out splendid. There will be enough for everyone and more.","TWN":"當然，酒都準備好囉，隊員們儘管喝都還有剩呢。"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"응? 술이라고요? 설마 그 감자 에일?","JPN":"うむ？　酒ですか？　まさか、あのジャガイモのエール？","ENG":"Hmm? Did you say, ale? Is that... spud ale?","TWN":"嗯？酒？是那個馬鈴薯啤酒嗎？"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};